// // This module implements a 4-to-1 multiplexer using if-else statements. The module has two 2-bit inputs 'a' and 'b', a 2-bit select input 'sel', and a 2-bit output 'out'. When 'sel' is 00, the value of 'out' is equal to the value of 'b' when 'sel' is 01, the value of 'out' is equal to the value of 'a' when 'sel' is 10, the value of 'out' is equal to the bitwise OR of 'a' and 'b', and when 'sel' is 11, the value of 'out' is equal to the bitwise AND of 'a' and 'b'.
module mux_4to1_if_else (
  input [1:0] a,
  input [1:0] b,
  input [1:0] sel,
  output reg [1:0] out
);

  always @(*) begin
    if(sel == 2'b00) begin
      out = a;
    end
    else if(sel == 2'b01) begin
      out = b;
    end
    else if(sel == 2'b10) begin
      out = a & b;
    end
    else begin // sel == 2'b11
      out = a | b;
    end
  end

endmodule
